/** RedFace Core Payment Engine — idempotency for all money-moving operations. */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type PaymentRequestType =
  | 'payment_session'
  | 'checkout'
  | 'refund'
  | 'refund_process'
  | 'quote_accept'
  | 'table_pay'
  | 'subscription'
  | 'store_credit';

export type PaymentRequestRow = {
  id: string;
  idempotency_key: string;
  merchant_id: string;
  request_type: string;
  status: string;
  customer_email: string | null;
  payment_session_id: string | null;
  transaction_reference: string | null;
  amount: number | null;
  currency: string | null;
  request_payload: Record<string, unknown>;
  response_payload: Record<string, unknown>;
  retry_count: number;
  created_at: string;
  updated_at: string;
  completed_at: string | null;
};

export type CheckoutIdentity = {
  reference: string;
  idempotencyKey: string;
  reused: boolean;
  alreadyPaid: boolean;
  retryCount: number;
  cachedResponse: Record<string, unknown> | null;
};

export function readIdempotencyKey(req: Request, body: Record<string, unknown>): string | null {
  const header = req.headers.get('Idempotency-Key')?.trim()
    || req.headers.get('X-Idempotency-Key')?.trim()
    || '';
  const bodyKey = String(body.idempotency_key ?? '').trim();
  return header || bodyKey || null;
}

export function ensureIdempotencyKey(existing: string | null | undefined): string {
  if (existing?.trim()) return existing.trim();
  return `rf_${crypto.randomUUID()}`;
}

export async function claimPaymentRequest(
  admin: SupabaseClient,
  opts: {
    merchantId: string;
    idempotencyKey: string;
    requestType: PaymentRequestType;
    customerEmail?: string | null;
    amount?: number | null;
    currency?: string | null;
    requestPayload?: Record<string, unknown>;
  },
): Promise<
  | { ok: true; created: boolean; retryCount: number; request: PaymentRequestRow }
  | { ok: false; error: string }
> {
  const { data, error } = await admin.rpc('claim_payment_request', {
    p_merchant_id: opts.merchantId,
    p_idempotency_key: opts.idempotencyKey,
    p_request_type: opts.requestType,
    p_customer_email: opts.customerEmail ?? null,
    p_amount: opts.amount ?? null,
    p_currency: opts.currency ?? null,
    p_request_payload: opts.requestPayload ?? {},
  });
  if (error) return { ok: false, error: error.message };
  const payload = data as {
    ok?: boolean;
    error?: string;
    created?: boolean;
    retry_count?: number;
    request?: PaymentRequestRow;
  };
  if (!payload?.ok || !payload.request) {
    return { ok: false, error: payload?.error ?? 'claim_failed' };
  }
  return {
    ok: true,
    created: !!payload.created,
    retryCount: Number(payload.retry_count ?? 0),
    request: payload.request,
  };
}

export async function completePaymentRequest(
  admin: SupabaseClient,
  opts: {
    merchantId: string;
    idempotencyKey: string;
    requestType: PaymentRequestType;
    status?: 'pending' | 'processing' | 'completed' | 'failed';
    paymentSessionId?: string | null;
    transactionReference?: string | null;
    responsePayload?: Record<string, unknown>;
  },
): Promise<void> {
  await admin.rpc('complete_payment_request', {
    p_merchant_id: opts.merchantId,
    p_idempotency_key: opts.idempotencyKey,
    p_request_type: opts.requestType,
    p_status: opts.status ?? 'completed',
    p_payment_session_id: opts.paymentSessionId ?? null,
    p_transaction_reference: opts.transactionReference ?? null,
    p_response_payload: opts.responsePayload ?? {},
  });
}

export async function getPaymentRequest(
  admin: SupabaseClient,
  merchantId: string,
  idempotencyKey: string,
  requestType?: PaymentRequestType,
): Promise<PaymentRequestRow | null> {
  const { data } = await admin.rpc('get_payment_request_by_idempotency', {
    p_merchant_id: merchantId,
    p_idempotency_key: idempotencyKey,
    p_request_type: requestType ?? null,
  });
  if (!data || typeof data !== 'object') return null;
  return data as PaymentRequestRow;
}

export async function resolveCheckoutIdentity(
  admin: SupabaseClient,
  req: Request,
  body: Record<string, unknown>,
  merchantId: string,
): Promise<CheckoutIdentity> {
  const idempotencyKey = ensureIdempotencyKey(readIdempotencyKey(req, body));

  const existingRequest = await getPaymentRequest(admin, merchantId, idempotencyKey, 'checkout');
  if (existingRequest?.status === 'completed' && existingRequest.response_payload) {
    const cached = existingRequest.response_payload;
    if (cached.already_paid || cached.authorization_url) {
      return {
        reference: String(existingRequest.transaction_reference ?? cached.reference ?? ''),
        idempotencyKey,
        reused: true,
        alreadyPaid: !!cached.already_paid,
        retryCount: existingRequest.retry_count,
        cachedResponse: cached,
      };
    }
  }

  const { data: existingRef } = await admin.rpc('get_payment_reference_by_idempotency', {
    p_key: idempotencyKey,
  });

  if (existingRef) {
    const { data: txn } = await admin
      .from('transactions')
      .select('status, reference')
      .eq('reference', existingRef)
      .maybeSingle();
    if (txn?.status === 'success') {
      await claimPaymentRequest(admin, {
        merchantId,
        idempotencyKey,
        requestType: 'checkout',
        customerEmail: String(body.email ?? '').trim() || null,
      });
      return {
        reference: String(existingRef),
        idempotencyKey,
        reused: true,
        alreadyPaid: true,
        retryCount: (existingRequest?.retry_count ?? 0) + 1,
        cachedResponse: { already_paid: true, reference: existingRef },
      };
    }
    if (txn?.status === 'pending') {
      const claim = await claimPaymentRequest(admin, {
        merchantId,
        idempotencyKey,
        requestType: 'checkout',
        customerEmail: String(body.email ?? '').trim() || null,
        amount: body.amount != null ? Number(body.amount) : null,
        currency: String(body.currency ?? 'ZAR'),
        requestPayload: { source: 'init_payment' },
      });
      return {
        reference: String(existingRef),
        idempotencyKey,
        reused: true,
        alreadyPaid: false,
        retryCount: claim.ok ? claim.retryCount : 0,
        cachedResponse: existingRequest?.response_payload ?? null,
      };
    }
  }

  await claimPaymentRequest(admin, {
    merchantId,
    idempotencyKey,
    requestType: 'checkout',
    customerEmail: String(body.email ?? '').trim() || null,
    amount: body.amount != null ? Number(body.amount) : null,
    currency: String(body.currency ?? 'ZAR'),
    requestPayload: { source: 'init_payment' },
  });

  return {
    reference: `rfp_${Date.now()}_${crypto.randomUUID().slice(0, 8)}`,
    idempotencyKey,
    reused: false,
    alreadyPaid: false,
    retryCount: 0,
    cachedResponse: null,
  };
}

export function idempotentSessionMessage(status: string): string | null {
  switch (status) {
    case 'waiting':
    case 'opened':
    case 'processing':
      return 'Payment already started. Waiting for customer…';
    case 'paid':
      return 'Payment already received.';
    case 'expired':
      return 'Previous payment session expired.';
    case 'cancelled':
      return 'Previous payment session was cancelled.';
    default:
      return null;
  }
}

/** Return cached response when an idempotent request already completed. */
export async function tryResumeCompletedRequest(
  admin: SupabaseClient,
  merchantId: string,
  idempotencyKey: string,
  requestType: PaymentRequestType,
  requestPayload?: Record<string, unknown>,
): Promise<
  | { hit: true; payload: Record<string, unknown>; retryCount: number }
  | { hit: false; retryCount: number }
> {
  const claim = await claimPaymentRequest(admin, {
    merchantId,
    idempotencyKey,
    requestType,
    requestPayload,
  });
  if (!claim.ok) return { hit: false, retryCount: 0 };

  const payload = claim.request.response_payload ?? {};
  const hasPayload = Object.keys(payload).length > 0;
  if (!claim.created && claim.request.status === 'completed' && hasPayload) {
    return { hit: true, payload, retryCount: claim.retryCount };
  }
  return { hit: false, retryCount: claim.retryCount };
}

/** Fare authorization — Takasit / mobility authorize-on-board, capture-on-complete. */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import {
  capturePaystackPreauthorization,
  releasePaystackPreauthorization,
} from './paystackApi.ts';

export type FareAuthRow = {
  id: string;
  merchant_id: string;
  reservation_id: string | null;
  amount_zar: number;
  captured_amount_zar: number | null;
  currency: string;
  label: string | null;
  status: string;
  payment_method: string | null;
  paystack_reference: string | null;
  paystack_preauth_reference: string | null;
  paystack_authorization_code: string | null;
  buyer_email: string | null;
  capture_reference: string | null;
  transaction_id: string | null;
  metadata: Record<string, unknown>;
};

export function buildFarePreauthReference(authorizationId: string): string {
  return `RFPR-${authorizationId.replace(/-/g, '').slice(0, 24)}`;
}

export async function createFareAuthorization(
  admin: SupabaseClient,
  opts: {
    merchantId: string;
    amountZar: number;
    currency?: string;
    label?: string;
    reservationId?: string;
    paymentMethod?: string;
    buyerEmail?: string;
    status?: string;
    paystackPreauthReference?: string;
    metadata?: Record<string, unknown>;
  },
): Promise<{ ok: true; row: FareAuthRow } | { ok: false; message: string }> {
  const { data: merchant } = await admin
    .from('merchants')
    .select('id, status')
    .eq('id', opts.merchantId)
    .maybeSingle();

  if (!merchant || merchant.status !== 'approved') {
    return { ok: false, message: 'Merchant not found or not approved' };
  }

  const amount = Number(opts.amountZar);
  if (!Number.isFinite(amount) || amount <= 0) {
    return { ok: false, message: 'amount must be greater than zero' };
  }

  const { data, error } = await admin
    .from('fare_authorizations')
    .insert({
      merchant_id: opts.merchantId,
      reservation_id: opts.reservationId?.trim() || null,
      amount_zar: amount,
      currency: opts.currency ?? 'ZAR',
      label: opts.label?.trim() || null,
      payment_method: opts.paymentMethod ?? 'redface',
      buyer_email: opts.buyerEmail?.trim().toLowerCase() || null,
      status: opts.status ?? 'authorized',
      paystack_preauth_reference: opts.paystackPreauthReference ?? null,
      metadata: {
        source: 'takasit',
        ...(opts.metadata ?? {}),
      },
    })
    .select()
    .single();

  if (error || !data) {
    return { ok: false, message: error?.message ?? 'Could not create authorization' };
  }

  return { ok: true, row: data as FareAuthRow };
}

export async function markFarePreauthReserved(
  admin: SupabaseClient,
  reference: string,
  patch: {
    authorizationCode?: string | null;
    buyerEmail?: string | null;
    fareAuthorizationId?: string | null;
  } = {},
): Promise<FareAuthRow | null> {
  const now = new Date().toISOString();
  const update = {
    status: 'authorized',
    paystack_preauth_reference: reference,
    paystack_reference: reference,
    paystack_authorization_code: patch.authorizationCode ?? null,
    buyer_email: patch.buyerEmail ?? null,
    authorized_at: now,
    updated_at: now,
  };

  const { data } = await admin
    .from('fare_authorizations')
    .update(update)
    .eq('paystack_preauth_reference', reference)
    .in('status', ['pending_preauth', 'authorized'])
    .select()
    .maybeSingle();

  if (data) return data as FareAuthRow;

  if (patch.fareAuthorizationId) {
    const { data: byId } = await admin
      .from('fare_authorizations')
      .update(update)
      .eq('id', patch.fareAuthorizationId)
      .in('status', ['pending_preauth', 'authorized'])
      .select()
      .maybeSingle();
    return (byId as FareAuthRow) ?? null;
  }

  return null;
}

export async function captureFareAuthorization(
  admin: SupabaseClient,
  opts: {
    authorizationId: string;
    merchantId?: string;
    amountZar?: number;
    recordOnly?: boolean;
    paystackSecret?: string;
    platformFee?: number;
  },
): Promise<{ ok: true; row: FareAuthRow } | { ok: false; message: string }> {
  let q = admin.from('fare_authorizations').select('*').eq('id', opts.authorizationId);
  if (opts.merchantId) q = q.eq('merchant_id', opts.merchantId);
  const { data: row, error } = await q.maybeSingle();

  if (error || !row) {
    return { ok: false, message: 'Authorization not found' };
  }

  const auth = row as FareAuthRow;
  if (auth.status === 'captured') {
    return { ok: true, row: auth };
  }
  if (!['authorized', 'capture_initiated'].includes(auth.status)) {
    return { ok: false, message: `Authorization is ${auth.status}` };
  }

  const captureAmount = opts.amountZar ?? Number(auth.amount_zar);
  const now = new Date().toISOString();

  if (opts.recordOnly || auth.payment_method === 'cash' || !auth.paystack_preauth_reference) {
    const { data: updated, error: upErr } = await admin
      .from('fare_authorizations')
      .update({
        status: 'captured',
        captured_amount_zar: captureAmount,
        captured_at: now,
        updated_at: now,
      })
      .eq('id', auth.id)
      .select()
      .single();
    if (upErr || !updated) {
      return { ok: false, message: upErr?.message ?? 'Capture failed' };
    }
    return { ok: true, row: updated as FareAuthRow };
  }

  if (!opts.paystackSecret) {
    return { ok: false, message: 'Paystack is not configured for capture.' };
  }

  const captureRef = auth.capture_reference ?? `takasit-cap-${auth.id}`;
  await admin.from('fare_authorizations').update({
    status: 'capture_initiated',
    captured_amount_zar: captureAmount,
    capture_reference: captureRef,
    updated_at: now,
  }).eq('id', auth.id);

  const ps = await capturePaystackPreauthorization(opts.paystackSecret, {
    reference: auth.paystack_preauth_reference,
    amountMajor: captureAmount,
    currency: auth.currency,
  });

  if (!ps.ok) {
    await admin.from('fare_authorizations').update({
      status: 'authorized',
      updated_at: new Date().toISOString(),
    }).eq('id', auth.id);
    return { ok: false, message: ps.message ?? 'Paystack capture failed' };
  }

  const psData = (ps.data ?? {}) as Record<string, unknown>;
  const txnReference = String(psData.reference ?? captureRef);
  const platformFee = opts.platformFee ?? 0;

  const { data: txn, error: txErr } = await admin.from('transactions').insert({
    merchant_id: auth.merchant_id,
    reference: txnReference,
    amount: captureAmount,
    card_amount: captureAmount,
    platform_fee: platformFee,
    currency: auth.currency,
    status: String(psData.status ?? 'success') === 'success' ? 'success' : 'pending',
    buyer_email: auth.buyer_email,
    buyer_authorised: true,
    buyer_authorised_at: now,
  }).select('id').single();

  if (txErr) {
    return { ok: false, message: txErr.message || 'Could not record capture transaction' };
  }

  const { data: updated, error: upErr } = await admin
    .from('fare_authorizations')
    .update({
      status: 'captured',
      captured_at: now,
      capture_reference: captureRef,
      paystack_reference: txnReference,
      transaction_id: txn?.id ?? null,
      updated_at: now,
    })
    .eq('id', auth.id)
    .select()
    .single();

  if (upErr || !updated) {
    return { ok: false, message: upErr?.message ?? 'Capture state update failed' };
  }

  return { ok: true, row: updated as FareAuthRow };
}

export async function releaseFareAuthorization(
  admin: SupabaseClient,
  opts: {
    authorizationId: string;
    merchantId?: string;
    paystackSecret?: string;
    recordOnly?: boolean;
  },
): Promise<{ ok: true; row: FareAuthRow } | { ok: false; message: string }> {
  let q = admin.from('fare_authorizations').select('*').eq('id', opts.authorizationId);
  if (opts.merchantId) q = q.eq('merchant_id', opts.merchantId);
  const { data: row } = await q.maybeSingle();
  if (!row) return { ok: false, message: 'Authorization not found' };

  const auth = row as FareAuthRow;
  if (auth.status === 'voided') return { ok: true, row: auth };
  if (auth.status === 'captured') {
    return { ok: false, message: 'Authorization already captured' };
  }

  if (auth.paystack_preauth_reference && opts.paystackSecret && !opts.recordOnly) {
    const ps = await releasePaystackPreauthorization(opts.paystackSecret, auth.paystack_preauth_reference);
    if (!ps.ok) {
      return { ok: false, message: ps.message ?? 'Paystack release failed' };
    }
  }

  const now = new Date().toISOString();
  const { data: updated, error } = await admin
    .from('fare_authorizations')
    .update({ status: 'voided', updated_at: now })
    .eq('id', auth.id)
    .select()
    .single();

  if (error || !updated) {
    return { ok: false, message: error?.message ?? 'Void failed' };
  }
  return { ok: true, row: updated as FareAuthRow };
}

export async function markFareAuthorizationCaptured(
  admin: SupabaseClient,
  captureReference: string,
  transactionId?: string,
): Promise<boolean> {
  const now = new Date().toISOString();
  const { data } = await admin
    .from('fare_authorizations')
    .update({
      status: 'captured',
      captured_at: now,
      updated_at: now,
      transaction_id: transactionId ?? null,
    })
    .eq('capture_reference', captureReference)
    .in('status', ['capture_initiated', 'authorized'])
    .select('id')
    .maybeSingle();
  return !!data;
}

export async function markFareAuthorizationCapturedById(
  admin: SupabaseClient,
  authorizationId: string,
  transactionId?: string,
): Promise<boolean> {
  const now = new Date().toISOString();
  const { data } = await admin
    .from('fare_authorizations')
    .update({
      status: 'captured',
      captured_at: now,
      updated_at: now,
      transaction_id: transactionId ?? null,
    })
    .eq('id', authorizationId)
    .in('status', ['capture_initiated', 'authorized', 'pending_preauth'])
    .select('id')
    .maybeSingle();
  return !!data;
}

export async function resolveFareAuthByPreauthReference(
  admin: SupabaseClient,
  reference: string,
): Promise<FareAuthRow | null> {
  const { data } = await admin
    .from('fare_authorizations')
    .select('*')
    .eq('paystack_preauth_reference', reference)
    .maybeSingle();
  return (data as FareAuthRow) ?? null;
}

/**
 * Merchant Capabilities API — registry-driven discovery (Capability Registry v1).
 *
 * Merchants buy outcomes; developers buy kernels. Response uses merchant-facing
 * keys only. Each capability is a feature contract: enabled + why/why not.
 *
 * @see docs/codex/platform/financial-abstraction-layer.md
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import {
  CAPABILITY_REGISTRY,
  type CapabilityDescriptor,
  type ProcessingRail,
  selectProcessingRail,
} from './paymentRouting.ts';
import { listPaymentTerminals, type PaymentTerminal } from './paymentTerminal.ts';

export type CapabilityState = {
  enabled: boolean;
  status: 'active' | 'unavailable' | 'planned';
  configured: boolean;
  requirements: string[];
  reason: string | null;
};

export type MerchantCapabilityMap = {
  paymentLinks: CapabilityState;
  qr: CapabilityState;
  nfcTap: CapabilityState;
  manualCard: CapabilityState;
  checkout: CapabilityState;
  tablePay: CapabilityState;
  cash: CapabilityState;
  storeCredit: CapabilityState;
  cardPayments: CapabilityState;
  bankTransfer: CapabilityState;
  crypto: CapabilityState;
  voiceCharge: CapabilityState;
  appleTap: CapabilityState;
  softpos: CapabilityState;
};

/** Flat booleans for simple UI checks. Prefer CapabilityState when showing reasons. */
export type MerchantCapabilityFlags = {
  [K in keyof MerchantCapabilityMap]: boolean;
};

export type MerchantCapabilitiesResponse = {
  merchant_id: string;
  country: string | null;
  currency: string;
  capabilities: MerchantCapabilityMap;
  /** Convenience booleans derived from capabilities.*.enabled */
  flags: MerchantCapabilityFlags;
  default_rails: Partial<Record<string, ProcessingRail>>;
  /** SoftPOS-ready terminals (NFC cards, SoftPOS, QR, cash, link). */
  terminals: PaymentTerminal[];
  registry: Array<CapabilityDescriptor & { available: boolean; missing_requirements: string[] }>;
};

type MerchantRow = {
  id: string;
  country: string | null;
  status: string;
  paystack_subaccount: string | null;
  paystack_split_code: string | null;
};

const REASON_LABEL: Record<string, string> = {
  merchant_approved: 'Business is not approved yet',
  country: 'Not available in this country',
  paystack_subaccount: 'Card payments are not set up yet',
  payment_object: 'No active terminal or NFC tag',
  store_credit_program: 'No active store credit issued yet',
  tap_partner_onboarding: 'Partner onboarding has not been completed',
  ios_device: 'Requires a compatible iPhone',
  planned: 'Coming soon',
  restaurant_tables: 'Floor tables are not set up',
  dedicated_account: 'Dedicated bank account is not active',
  crypto_wallets: 'Crypto wallets are not configured',
};

function hasPaystackRoute(m: MerchantRow): boolean {
  return String(m.paystack_split_code || m.paystack_subaccount || '').trim().length > 0;
}

function countryAllowed(desc: CapabilityDescriptor, country: string | null): boolean {
  if (desc.countries === 'all') return true;
  const c = String(country ?? '').trim().toUpperCase();
  return desc.countries.some((x) => x.toUpperCase() === c);
}

function evaluateDescriptor(
  desc: CapabilityDescriptor,
  ctx: {
    merchant: MerchantRow;
    hasPaymentObject: boolean;
    hasTables: boolean;
    hasStoreCreditProgram: boolean;
    hasDedicatedAccount: boolean;
    hasCrypto: boolean;
  },
): { available: boolean; missing: string[] } {
  const missing: string[] = [];
  if (ctx.merchant.status !== 'approved') missing.push('merchant_approved');
  if (!countryAllowed(desc, ctx.merchant.country)) missing.push('country');

  for (const req of desc.requirements) {
    if (req === 'paystack_subaccount' && !hasPaystackRoute(ctx.merchant)) missing.push(req);
    if (req === 'payment_object' && !ctx.hasPaymentObject) missing.push(req);
    if (req === 'store_credit_program' && !ctx.hasStoreCreditProgram) missing.push(req);
    if (req === 'dedicated_account' && !ctx.hasDedicatedAccount) missing.push(req);
    if (req === 'crypto_wallets' && !ctx.hasCrypto) missing.push(req);
    if (req === 'tap_partner_onboarding') missing.push(req);
    if (req === 'ios_device') missing.push(req);
  }

  if (desc.id === 'store_credit_rail' || desc.id === 'store_credit_capture') {
    if (!ctx.hasStoreCreditProgram) missing.push('store_credit_program');
  }
  if (desc.status === 'planned') missing.push('planned');

  return { available: missing.length === 0, missing: [...new Set(missing)] };
}

function toState(
  enabled: boolean,
  missing: string[],
  opts: { planned?: boolean; configured?: boolean } = {},
): CapabilityState {
  const requirements = missing.filter((m) => m !== 'planned' && m !== 'merchant_approved');
  const primary = missing[0] ?? null;
  return {
    enabled,
    status: opts.planned || missing.includes('planned')
      ? 'planned'
      : enabled
        ? 'active'
        : 'unavailable',
    configured: opts.configured ?? enabled,
    requirements,
    reason: enabled ? null : (primary ? (REASON_LABEL[primary] ?? primary) : 'Unavailable'),
  };
}

function flagsFromMap(map: MerchantCapabilityMap): MerchantCapabilityFlags {
  return Object.fromEntries(
    Object.entries(map).map(([k, v]) => [k, (v as CapabilityState).enabled]),
  ) as MerchantCapabilityFlags;
}

export async function resolveMerchantCapabilities(
  admin: SupabaseClient,
  merchantId: string,
): Promise<{ ok: true; data: MerchantCapabilitiesResponse } | { ok: false; error: string }> {
  const id = String(merchantId ?? '').trim();
  if (!id) return { ok: false, error: 'merchant_id_required' };

  const { data: merchant, error } = await admin
    .from('merchants')
    .select('id, country, status, paystack_subaccount, paystack_split_code')
    .eq('id', id)
    .maybeSingle();
  if (error || !merchant) return { ok: false, error: 'merchant_not_found' };

  const [
    { count: poCount },
    { count: tableCount },
    { count: creditCount },
    { count: dedicatedCount },
    { data: cryptoRow },
  ] = await Promise.all([
    admin.from('payment_objects').select('id', { count: 'exact', head: true })
      .eq('merchant_id', id).eq('status', 'active'),
    admin.from('restaurant_tables').select('id', { count: 'exact', head: true })
      .eq('merchant_id', id),
    admin.from('merchant_store_credits').select('id', { count: 'exact', head: true })
      .eq('merchant_id', id).eq('status', 'active'),
    admin.from('merchant_dedicated_accounts').select('id', { count: 'exact', head: true })
      .eq('merchant_id', id).eq('status', 'active'),
    admin.from('merchant_crypto_settings').select('enabled, btc_address, eth_address, usdt_trc20_address, usdt_erc20_address')
      .eq('merchant_id', id).maybeSingle(),
  ]);

  const hasCrypto = Boolean(
    cryptoRow?.enabled
    && (cryptoRow.btc_address || cryptoRow.eth_address || cryptoRow.usdt_trc20_address || cryptoRow.usdt_erc20_address),
  );

  const ctx = {
    merchant: merchant as MerchantRow,
    hasPaymentObject: (poCount ?? 0) > 0,
    hasTables: (tableCount ?? 0) > 0,
    hasStoreCreditProgram: (creditCount ?? 0) > 0,
    hasDedicatedAccount: (dedicatedCount ?? 0) > 0,
    hasCrypto,
  };

  const country = merchant.country ?? null;
  const currency = country === 'NG' ? 'NGN' : country === 'GH' ? 'GHS' : country === 'KE' ? 'KES' : 'ZAR';

  const registry = CAPABILITY_REGISTRY.map((desc) => {
    const { available, missing } = evaluateDescriptor(desc, ctx);
    return { ...desc, available, missing_requirements: missing };
  });

  const byId = (capId: string) => registry.find((r) => r.id === capId);

  const paymentLink = byId('payment_link_capture');
  const qr = byId('qr_capture');
  const nfc = byId('nfc_tap_capture');
  const manual = byId('manual_card_capture');
  const cash = byId('cash_capture');
  const storeCredit = byId('store_credit_capture') ?? byId('store_credit_rail');
  const paystack = byId('paystack_rail');
  const apple = byId('apple_tap_capture');
  const softpos = byId('softpos_capture');
  const bank = byId('bank_transfer_capture');
  const crypto = byId('crypto_capture');

  const cardPayments = paystack?.available ?? false;

  const capabilities: MerchantCapabilityMap = {
    paymentLinks: toState(paymentLink?.available ?? false, paymentLink?.missing_requirements ?? []),
    qr: toState(qr?.available ?? false, qr?.missing_requirements ?? []),
    nfcTap: toState(nfc?.available ?? false, nfc?.missing_requirements ?? [], {
      configured: ctx.hasPaymentObject,
    }),
    manualCard: toState(
      (manual?.available ?? false) && cardPayments,
      [...(manual?.missing_requirements ?? []), ...(cardPayments ? [] : ['paystack_subaccount'])],
    ),
    checkout: toState(cardPayments || (paymentLink?.available ?? false), cardPayments ? [] : ['paystack_subaccount']),
    tablePay: toState(
      ctx.hasTables && (paymentLink?.available ?? false),
      ctx.hasTables ? (paymentLink?.missing_requirements ?? []) : ['restaurant_tables'],
      { configured: ctx.hasTables },
    ),
    cash: toState(cash?.available ?? false, cash?.missing_requirements ?? []),
    storeCredit: toState(storeCredit?.available ?? false, storeCredit?.missing_requirements ?? [], {
      configured: ctx.hasStoreCreditProgram,
    }),
    cardPayments: toState(cardPayments, paystack?.missing_requirements ?? [], {
      configured: hasPaystackRoute(merchant as MerchantRow),
    }),
    bankTransfer: toState(bank?.available ?? false, bank?.missing_requirements ?? [], {
      configured: ctx.hasDedicatedAccount,
    }),
    crypto: toState(crypto?.available ?? false, crypto?.missing_requirements ?? [], {
      configured: hasCrypto,
    }),
    voiceCharge: toState(paymentLink?.available ?? false, paymentLink?.missing_requirements ?? []),
    appleTap: toState(apple?.available ?? false, apple?.missing_requirements ?? [], { planned: true }),
    softpos: toState(softpos?.available ?? false, softpos?.missing_requirements ?? [], { planned: true }),
  };

  const default_rails: Partial<Record<string, ProcessingRail>> = {
    payment_link: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'payment_link' }).rail,
    nfc_tap: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'nfc_tap' }).rail,
    cash: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'cash' }).rail,
    store_credit: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'store_credit' }).rail,
    softpos: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'softpos' }).rail,
    apple_tap: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'apple_tap' }).rail,
  };

  const terminals = await listPaymentTerminals(admin, id, { includeSynthetic: true });

  return {
    ok: true,
    data: {
      merchant_id: id,
      country,
      currency,
      capabilities,
      flags: flagsFromMap(capabilities),
      default_rails,
      terminals,
      registry,
    },
  };
}

/**
 * Capability Registry + Routing & Policy Engine (v2).
 *
 * Business modules never choose providers (Platform Invariant V). They state
 * a Business Intent and a capture method; the router selects the processing
 * rail. SoftPOS is a capability; Stripe Terminal / SA SoftPOS partners implement
 * it. Paystack remains the default SA online rail.
 *
 * Vocabulary: docs/codex/platform/financial-abstraction-layer.md
 * SoftPOS: `_shared/softpos/` · ADR-017
 */

import { isStripeTerminalTtpCountry, resolveSoftposOffer } from './softpos/countryGate.ts';

export type CaptureMethod =
  | 'qr'
  | 'nfc_tap'
  | 'payment_link'
  | 'manual_card'
  | 'checkout'
  | 'table_pay'
  | 'cash'
  | 'store_credit'
  | 'apple_tap'
  | 'softpos'
  | 'google_tap'
  | 'external_terminal';

/**
 * Processing rails — who moves the money.
 * SoftPOS: stripe_terminal (where Terminal TTP is supported) or SA partners
 * (istore_tap / yoco_tap). Online SA defaults to paystack.
 */
export type ProcessingRail =
  | 'paystack'
  | 'stripe'
  | 'stripe_terminal'
  | 'cash'
  | 'store_credit'
  | 'wallet'
  | 'istore_tap'
  | 'yoco_tap';

export type CapabilityDescriptor = {
  id: string;
  kind: 'capture' | 'rail';
  label: string;
  countries: string[] | 'all';
  currencies: string[] | 'all';
  /** Requirements a merchant must satisfy before the capability is offered. */
  requirements: string[];
  status: 'active' | 'planned';
  /** Optional: which capture methods this rail can settle. */
  supportsCapture?: CaptureMethod[];
};

