export type SoftposPartner = 'istore_tap' | 'yoco_tap' | 'stripe_terminal' | null;

export type RoutingContext = {
  merchantId: string;
  currency?: string | null;
  country?: string | null;
  captureMethod?: CaptureMethod | string | null;
  businessIntent?: string | null;
  /** When SoftPOS partner onboarding is complete, set the live partner id. */
  softposPartner?: SoftposPartner;
  /** Merchant entitled to Stripe Terminal SoftPOS (after Stripe confirms). */
  stripeTerminalEntitled?: boolean;
  /** Ops override — support tooling only. */
  forceRail?: ProcessingRail | null;
};

export type RoutingDecision = {
  rail: ProcessingRail;
  reason: string;
  /** True when a planned SoftPOS rail was preferred but is not live yet. */
  fallback?: boolean;
  plannedRail?: ProcessingRail | null;
  captureMethod: string;
  decidedAt: string;
};

const PAYSTACK_COUNTRIES = new Set(['ZA', 'NG', 'GH', 'KE']);

function normalizeCountry(country?: string | null): string {
  return String(country ?? 'ZA').trim().toUpperCase() || 'ZA';
}

function normalizeCurrency(currency?: string | null, country?: string): string {
  const c = String(currency ?? '').trim().toUpperCase();
  if (c) return c;
  if (country === 'NG') return 'NGN';
  if (country === 'GH') return 'GHS';
  if (country === 'KE') return 'KES';
  return 'ZAR';
}

function isSoftposCapture(capture: string): boolean {
  return capture === 'apple_tap' || capture === 'softpos' || capture === 'google_tap';
}

/**
 * Routing & Policy Engine v2.
 * Deterministic rules; SoftPOS partners register as planned until entitlement.
 * Provider health / cost / auth-rate signals arrive with the second live acquirer.
 */
export function selectProcessingRail(ctx: RoutingContext): RoutingDecision {
  const capture = String(ctx.captureMethod ?? '').trim().toLowerCase() || 'payment_link';
  const country = normalizeCountry(ctx.country);
  const currency = normalizeCurrency(ctx.currency, country);
  const decidedAt = new Date().toISOString();

  if (ctx.forceRail) {
    return {
      rail: ctx.forceRail,
      reason: `ops override → ${ctx.forceRail}`,
      captureMethod: capture,
      decidedAt,
    };
  }

  if (capture === 'cash') {
    return {
      rail: 'cash',
      reason: 'cash capture settles internally on the merchant ledger',
      captureMethod: capture,
      decidedAt,
    };
  }
  if (capture === 'store_credit') {
    return {
      rail: 'store_credit',
      reason: 'store credit settles against the merchant liability ledger',
      captureMethod: capture,
      decidedAt,
    };
  }

  // SoftPOS / Tap to Pay — capability; provider selected by country + entitlement.
  // Never assume Swiss Stripe platform ⇒ SoftPOS for ZA operating merchants.
  if (isSoftposCapture(capture)) {
    const saPartner =
      ctx.softposPartner === 'istore_tap' || ctx.softposPartner === 'yoco_tap'
        ? ctx.softposPartner
        : null;
    const stripeEntitled =
      Boolean(ctx.stripeTerminalEntitled) || ctx.softposPartner === 'stripe_terminal';
    const offer = resolveSoftposOffer({
      country,
      stripeTerminalEntitled: stripeEntitled,
      saPartner,
    });

    if (offer.offered && offer.providerId === 'istore_tap') {
      return {
        rail: 'istore_tap',
        reason: offer.reason,
        captureMethod: capture,
        decidedAt,
      };
    }
    if (offer.offered && offer.providerId === 'yoco_tap') {
      return {
        rail: 'yoco_tap',
        reason: offer.reason,
        captureMethod: capture,
        decidedAt,
      };
    }
    if (offer.offered && offer.providerId === 'stripe_terminal') {
      return {
        rail: 'stripe_terminal',
        reason: offer.reason,
        captureMethod: capture,
        decidedAt,
      };
    }

    const plannedRail: ProcessingRail | null =
      country === 'ZA'
        ? 'istore_tap'
        : isStripeTerminalTtpCountry(country)
          ? 'stripe_terminal'
          : null;

    // SoftPOS is not live — do not route in-person tap to Paystack SoftPOS.
    // Online SA capture still uses Paystack via link/QR/checkout actions.
    return {
      rail: PAYSTACK_COUNTRIES.has(country) ? 'paystack' : 'stripe',
      reason: offer.reason,
      fallback: true,
      plannedRail,
      captureMethod: capture,
      decidedAt,
    };
  }

  // Country-aware default acquiring (online / QR / links / checkout)
  if (PAYSTACK_COUNTRIES.has(country)) {
    return {
      rail: 'paystack',
      reason: `default SA/Africa online acquiring rail for ${country}/${currency}`,
      captureMethod: capture,
      decidedAt,
    };
  }

  // Non-Paystack countries: Stripe Checkout when configured, else Paystack fallback label.
  return {
    rail: 'stripe',
    reason: `international online rail for ${country}/${currency} (Stripe Checkout when active)`,
    captureMethod: capture,
    decidedAt,
  };
}

export function listActiveCapabilities(kind?: 'capture' | 'rail'): CapabilityDescriptor[] {
  return CAPABILITY_REGISTRY.filter(
    (c) => c.status === 'active' && (kind ? c.kind === kind : true),
  );
}

export function listPlannedCapabilities(kind?: 'capture' | 'rail'): CapabilityDescriptor[] {
  return CAPABILITY_REGISTRY.filter(
    (c) => c.status === 'planned' && (kind ? c.kind === kind : true),
  );
}

/** Serialize a routing decision for payment_sessions.metadata.routing */
export function routingDecisionToMeta(decision: RoutingDecision): Record<string, unknown> {
  return {
    rail: decision.rail,
    reason: decision.reason,
    capture_method: decision.captureMethod,
    decided_at: decision.decidedAt,
    ...(decision.fallback ? { fallback: true } : {}),
    ...(decision.plannedRail ? { planned_rail: decision.plannedRail } : {}),
  };
}

/** Payment Session helpers — terminal mode (merchant Ready → customer tap). */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { cartLabel, resolveCartItems, type CartLine } from './cartItems.ts';
import {
  claimPaymentRequest,
  completePaymentRequest,
  idempotentSessionMessage,
} from './idempotency.ts';
import { recordPaymentLedgerEntry } from './ledgerEngine.ts';
import { selectProcessingRail, routingDecisionToMeta } from './paymentRouting.ts';

export type { CartLine };
export { cartLabel, resolveCartItems };

const ACTIVE_SESSION_STATUSES = new Set(['waiting', 'opened', 'processing']);

export function isActivePaymentSessionStatus(status: string): boolean {
  return ACTIVE_SESSION_STATUSES.has(status);
}

export type PaymentSessionRow = {
  id: string;
  merchant_id: string;
  payment_object_id: string | null;
  public_token: string;
  amount: number;
  currency: string;
  label: string | null;
  status: string;
  expires_at: string;
  metadata?: Record<string, unknown> | null;
};

export async function cancelOpenSessions(
  admin: SupabaseClient,
  merchantId: string,
  paymentObjectId: string | null,
) {
  let q = admin
    .from('payment_sessions')
    .update({ status: 'cancelled', updated_at: new Date().toISOString() })
    .eq('merchant_id', merchantId)
    .in('status', ['waiting', 'opened', 'processing']);
  if (paymentObjectId) {
    q = q.eq('payment_object_id', paymentObjectId);
  } else {
    q = q.is('payment_object_id', null);
  }
  await q;
}

export async function validatePaymentSessionForInit(
  admin: SupabaseClient,
  opts: {
    sessionId?: string | null;
    sessionToken?: string | null;
    merchantId: string;
    amount: number;
    reference: string;
  },
): Promise<{ ok: true; session: PaymentSessionRow } | { ok: false; message: string }> {
  const { sessionId, sessionToken, merchantId, amount, reference } = opts;
  if (!sessionId && !sessionToken) {
    return { ok: false, message: 'payment_session required' };
  }

  await admin.rpc('expire_payment_sessions').then(() => {}, () => {});

  let q = admin
    .from('payment_sessions')
    .select('id, merchant_id, payment_object_id, public_token, amount, currency, label, status, expires_at')
    .eq('merchant_id', merchantId)
    .in('status', ['waiting', 'opened', 'processing'])
    .gt('expires_at', new Date().toISOString());

  if (sessionId) q = q.eq('id', sessionId);
  else if (sessionToken) q = q.eq('public_token', sessionToken);
  else return { ok: false, message: 'payment_session required' };

  const { data: session, error } = await q.maybeSingle();
  if (error || !session) {
    return { ok: false, message: 'Payment session not found or expired. Ask the merchant to press Ready again.' };
  }

  const sessionAmount = Number(session.amount);
  if (Math.abs(sessionAmount - amount) > 0.009) {
    return {
      ok: false,
      message: `Amount must match the merchant session (${sessionAmount} ${session.currency}).`,
    };
  }

  await admin.rpc('mark_payment_session_processing', {
    p_session_id: session.id,
    p_reference: reference,
  });

  return { ok: true, session: session as PaymentSessionRow };
}

export async function markSessionPaid(
  admin: SupabaseClient,
  reference: string,
  transactionId?: string | null,
) {
  await admin.rpc('mark_payment_session_paid', {
    p_reference: reference,
    p_transaction_id: transactionId ?? null,
  });
  // Ledger commitment: providers are evidence, the Ledger is truth.
  // Idempotent — duplicate webhooks and sync/async races collapse into one entry.
  await recordPaymentLedgerEntry(admin, { reference });
}

export async function markSessionFailed(admin: SupabaseClient, reference: string) {
  await admin.rpc('mark_payment_session_failed', { p_reference: reference });
}

export async function reopenPaymentSession(admin: SupabaseClient, sessionId: string) {
  await admin.rpc('mark_payment_session_reopen', { p_session_id: sessionId });
}

const SESSION_SELECT =
  'id, public_token, amount, currency, label, status, expires_at, payment_object_id, cart_items';

export async function createPaymentSessionRecord(
  admin: SupabaseClient,
  opts: {
    merchantId: string;
    amount?: number;
    currency?: string;
    label?: string | null;
    paymentObjectId?: string | null;
    ttlSeconds?: number;
    cartItems?: unknown;
    createdBy?: string | null;
    idempotencyKey?: string | null;
    requestType?: 'payment_session' | 'table_pay';
    metadata?: Record<string, unknown> | null;
    /** WHAT the merchant wants to achieve (never a provider). Defaults to collect_payment. */
    businessIntent?: string | null;
    /** HOW the customer will authorise, when known at creation (qr, nfc_tap, table_pay, ...). */
    captureMethod?: string | null;
    /** Merchant operating country for Routing Engine (ISO 3166-1 alpha-2). */
    country?: string | null;
    softposPartner?: 'istore_tap' | 'yoco_tap' | 'stripe_terminal' | null;
    stripeTerminalEntitled?: boolean;
  },
): Promise<
  | {
    ok: true;
    session: Record<string, unknown>;
    cartItems: CartLine[];
    idempotent?: boolean;
    retryCount?: number;
    message?: string | null;
  }
  | { ok: false; error: string; status?: number }
> {
  let amount = Number(opts.amount ?? 0);
  const currency = String(opts.currency ?? 'ZAR').trim() || 'ZAR';
  let label = String(opts.label ?? '').trim() || null;
  let paymentObjectId = String(opts.paymentObjectId ?? '').trim() || null;
  const ttlSeconds = Math.min(3600, Math.max(60, Number(opts.ttlSeconds ?? 900)));
  let cartItemsStored: CartLine[] = [];

  if (opts.cartItems != null && Array.isArray(opts.cartItems) && opts.cartItems.length > 0) {
    const resolved = await resolveCartItems(admin, opts.merchantId, opts.cartItems);
    if ('error' in resolved) return { ok: false, error: resolved.error, status: 400 };
    amount = resolved.total;
    cartItemsStored = resolved.items;
  }

  if (!amount || amount <= 0) {
    return { ok: false, error: 'amount is required', status: 400 };
  }

  const idempotencyKey = String(opts.idempotencyKey ?? '').trim() || null;
  const requestType = opts.requestType ?? 'payment_session';

  if (idempotencyKey) {
    const claim = await claimPaymentRequest(admin, {
      merchantId: opts.merchantId,
      idempotencyKey,
      requestType,
      amount,
      currency,
      requestPayload: {
        label,
        payment_object_id: paymentObjectId,
        cart_count: cartItemsStored.length,
      },
    });
    if (claim.ok && !claim.created && claim.request.payment_session_id) {
      const { data: existing } = await admin
        .from('payment_sessions')
        .select(SESSION_SELECT)
        .eq('id', claim.request.payment_session_id)
        .eq('merchant_id', opts.merchantId)
        .maybeSingle();
      if (existing) {
        const storedCart = Array.isArray(existing.cart_items) ? existing.cart_items as CartLine[] : cartItemsStored;
        if (isActivePaymentSessionStatus(String(existing.status))) {
          return {
            ok: true,
            session: existing,
            cartItems: storedCart,
            idempotent: true,
            retryCount: claim.retryCount,
            message: idempotentSessionMessage(String(existing.status)),
          };
        }
        // Stale idempotency (paid / expired / cancelled) — create a fresh session below.
      }
    }
  }

  if (!paymentObjectId) {
    const { data: primary } = await admin
      .from('payment_objects')
      .select('id')
      .eq('merchant_id', opts.merchantId)
      .eq('status', 'active')
      .order('created_at', { ascending: true })
      .limit(1)
      .maybeSingle();
    paymentObjectId = primary?.id ?? null;
  }

  let terminalLabel: string | null = null;
  let terminalTapCode: string | null = null;
  if (paymentObjectId) {
    const { data: obj } = await admin
      .from('payment_objects')
      .select('id, label, tap_code')
      .eq('id', paymentObjectId)
      .eq('merchant_id', opts.merchantId)
      .eq('status', 'active')
      .maybeSingle();
    if (!obj) return { ok: false, error: 'Terminal not found', status: 404 };
    terminalLabel = obj.label ? String(obj.label) : null;
    terminalTapCode = obj.tap_code ? String(obj.tap_code) : null;
  }

  await admin.rpc('expire_payment_sessions').then(() => {}, () => {});
  await cancelOpenSessions(admin, opts.merchantId, paymentObjectId);

  const expiresAt = new Date(Date.now() + ttlSeconds * 1000).toISOString();
  const rawMetadata = opts.metadata && typeof opts.metadata === 'object'
    ? opts.metadata
    : {};
  // Commerce Intelligence: every session carries enough business context to
  // explain who / what / where — notes are never the only source of truth.
  const sessionMetadata: Record<string, unknown> = {
    ...rawMetadata,
  };
  if (paymentObjectId) {
    sessionMetadata.payment_object_id = paymentObjectId;
    if (terminalLabel) sessionMetadata.terminal_label = terminalLabel;
    if (terminalTapCode) sessionMetadata.terminal_tap_code = terminalTapCode;
  }
  if (cartItemsStored.length) {
    sessionMetadata.line_item_count = cartItemsStored.length;
    sessionMetadata.has_line_items = true;
  }
  const hasPosSale = Boolean(String(sessionMetadata.pos_sale_id ?? '').trim());
  const hasCart = cartItemsStored.length > 0;
  const businessIntent = String(opts.businessIntent ?? '').trim().toLowerCase()
    || (requestType === 'table_pay' || hasPosSale || hasCart ? 'complete_sale' : 'collect_payment');
  let captureMethod = String(opts.captureMethod ?? '').trim().toLowerCase() || null;
  if (!captureMethod) {
    if (requestType === 'table_pay') captureMethod = 'table_pay';
    else if (paymentObjectId) captureMethod = 'nfc_tap';
    else if (hasPosSale) captureMethod = 'checkout';
    else captureMethod = 'payment_link';
  }
  sessionMetadata.business_intent = businessIntent;
  sessionMetadata.capture_method = captureMethod;
  const routing = selectProcessingRail({
    merchantId: opts.merchantId,
    currency,
    country: opts.country ?? null,
    captureMethod,
    businessIntent,
    softposPartner: opts.softposPartner ?? null,
    stripeTerminalEntitled: opts.stripeTerminalEntitled,
  });
  sessionMetadata.routing = routingDecisionToMeta(routing);
  sessionMetadata.processing_rail = routing.rail;
  const { data: row, error } = await admin.from('payment_sessions').insert({
    merchant_id: opts.merchantId,
    payment_object_id: paymentObjectId,
    amount,
    currency,
    label: label || (cartItemsStored.length ? cartLabel(cartItemsStored) : null),
    cart_items: cartItemsStored,
    metadata: sessionMetadata,
    status: 'waiting',
    expires_at: expiresAt,
    created_by: opts.createdBy ?? null,
    business_intent: businessIntent,
    capture_method: captureMethod,
    processing_rail: routing.rail,
  }).select(SESSION_SELECT).single();

  if (error || !row) {
    return { ok: false, error: error?.message || 'Could not create payment session', status: 500 };
  }

  if (idempotencyKey) {
    await completePaymentRequest(admin, {
      merchantId: opts.merchantId,
      idempotencyKey,
      requestType,
      status: 'processing',
      paymentSessionId: String(row.id),
      responsePayload: { session: row },
    });
  }

  return { ok: true, session: row, cartItems: cartItemsStored, idempotent: false, retryCount: 0 };
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

const PLATFORM_OWNER_EMAIL = 'info@redfacepay.co.za';

export function isPlatformOwnerEmail(email: string | null | undefined): boolean {
  return String(email ?? '').trim().toLowerCase() === PLATFORM_OWNER_EMAIL;
}

export type MerchantAutoApproveRow = {
  id: string;
  status: string;
  business_name: string | null;
  email: string | null;
  owner_name: string | null;
  account_name: string | null;
  account_verified: boolean | null;
  account_verified_by: string | null;
  bank_code: string | null;
  bank_account: string | null;
  kyc_doc: string | null;
  legal_status: string | null;
  permit_number: string | null;
  sells_restricted_goods: boolean | null;
  paystack_subaccount: string | null;
};

export type AutoApproveAssessment = {
  eligible: boolean;
  blockers: string[];
  reasons: string[];
};

function normalizeNamePart(s: string): string {
  return s
    .toLowerCase()
    .replace(/\b(pty|ltd|cc|inc|npc|npo|trust)\b/g, '')
    .replace(/[^a-z0-9]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

/** Loose match — bank account holder vs business or owner name. */
export function bankAccountNameAligns(
  accountName: string | null | undefined,
  businessName: string | null | undefined,
  ownerName: string | null | undefined,
): boolean {
  const account = normalizeNamePart(String(accountName ?? ''));
  if (!account) return true;
  const business = normalizeNamePart(String(businessName ?? ''));
  const owner = normalizeNamePart(String(ownerName ?? ''));
  if (business && (account.includes(business) || business.includes(account))) return true;
  if (owner && (account.includes(owner) || owner.includes(account))) return true;
  const ownerParts = owner.split(' ').filter((p) => p.length > 2);
  if (ownerParts.some((p) => account.includes(p))) return true;
  return false;
}

export function assessMerchantForAutoApprove(
  m: MerchantAutoApproveRow,
  identityDocCount: number,
): AutoApproveAssessment {
  const blockers: string[] = [];
  const reasons: string[] = [];

  if (m.status !== 'pending') blockers.push('already_reviewed');
  if (!m.account_verified) blockers.push('bank_not_verified');
  if (!m.bank_code?.trim() || !m.bank_account?.trim()) blockers.push('bank_incomplete');
  if (!m.kyc_doc?.trim() && identityDocCount < 1) blockers.push('identity_docs_missing');
  if (!m.business_name?.trim()) blockers.push('business_name_missing');
  if (!m.owner_name?.trim()) blockers.push('owner_name_missing');
  if (!m.email?.trim()) blockers.push('email_missing');
  if (m.sells_restricted_goods) blockers.push('restricted_goods_review');

  if (['foreign_national', 'refugee_asylum'].includes(String(m.legal_status ?? '')) && !m.permit_number?.trim()) {
    blockers.push('permit_required');
  }

  if (m.account_verified && m.account_verified_by === 'admin') {
    reasons.push('bank_verified_by_admin');
  } else if (m.account_verified) {
    reasons.push('bank_verified_paystack');
  }

  if (m.kyc_doc?.trim() || identityDocCount > 0) reasons.push('identity_on_file');

  if (
    m.account_name?.trim()
    && !bankAccountNameAligns(m.account_name, m.business_name, m.owner_name)
  ) {
    blockers.push('account_name_mismatch');
  } else if (m.account_name?.trim()) {
    reasons.push('account_name_matches_business');
  }

  return { eligible: blockers.length === 0, blockers, reasons };
}

export type ProvisionResult = {
  ok: boolean;
  message?: string;
  subaccount?: string | null;
  tag_code?: string | null;
  already_approved?: boolean;
};

export async function provisionMerchantPayouts(
  admin: SupabaseClient,
  paystackPost: (path: string, body: unknown) => Promise<Record<string, unknown>>,
  opts: {
    merchantId: string;
    actorEmail?: string | null;
    decisionReason?: string;
    decisionNotes?: string | null;
    manualSubaccountCode?: string;
    platformFeePercent: number;
    sendWelcomeEmail: (args: {
      email: string;
      businessName: string;
      tagCode: string;
    }) => Promise<void>;
  },
): Promise<ProvisionResult> {
  const merchantId = opts.merchantId;
  const { data: merchant } = await admin
    .from('merchants')
    .select(
      'id, business_name, email, bank_code, bank_account, paystack_subaccount, status, legal_status, permit_number, permit_expiry, offering_type, primary_products, expected_monthly_volume, sells_restricted_goods, risk_level, account_verified',
    )
    .eq('id', merchantId)
    .maybeSingle();

  if (!merchant) return { ok: false, message: 'Merchant not found' };

  const existingRoute = String(merchant.paystack_subaccount ?? '').trim();
  const hasLiveRoute = existingRoute.startsWith('ACCT_') || existingRoute.startsWith('SPL_');

  // Already approved with a real settlement route — idempotent success.
  if (merchant.status === 'approved' && hasLiveRoute) {
    return { ok: true, already_approved: true, subaccount: existingRoute };
  }

  // Platform owner settles on the main Paystack account — never create a subaccount.
  if (isPlatformOwnerEmail(String(merchant.email ?? ''))) {
    const { data: existingTag } = await admin
      .from('nfc_tags')
      .select('tag_code')
      .eq('merchant_id', merchantId)
      .maybeSingle();
    const tagCode = existingTag?.tag_code ?? `RFP-${crypto.randomUUID().slice(0, 8).toUpperCase()}`;

    await admin
      .from('merchants')
      .update({
        paystack_subaccount: null,
        paystack_split_code: null,
        status: 'approved',
        account_verified: true,
        account_verified_by: merchant.account_verified_by ?? 'admin',
      })
      .eq('id', merchantId);

    if (!existingTag) {
      await admin.from('nfc_tags').insert({ merchant_id: merchantId, tag_code: tagCode, status: 'active' });
    }

    await admin.from('admin_actions').insert({
      action_type: opts.actorEmail ? 'approve_merchant' : 'auto_approve_merchant',
      merchant_id: merchantId,
      actor_email: opts.actorEmail ?? null,
      decision_reason: opts.decisionReason || 'Platform owner — main Paystack account (no subaccount)',
      decision_notes: opts.decisionNotes ?? null,
      compliance_snapshot: {
        platform_owner: true,
        paystack_subaccount: null,
        auto: !opts.actorEmail,
      },
    });

    if (merchant.email) {
      await opts.sendWelcomeEmail({
        email: String(merchant.email),
        businessName: String(merchant.business_name),
        tagCode,
      });
    }

    return { ok: true, subaccount: null, tag_code: tagCode };
  }

  const manualCode = String(opts.manualSubaccountCode ?? '').trim();
  const existingCode = (merchant.paystack_subaccount as string | null) || '';
  let subaccountCode: string | null =
    manualCode ||
    (existingCode.startsWith('ACCT_') || existingCode.startsWith('SPL_') ? existingCode : null);

  if (!subaccountCode) {
    if (!merchant.bank_code || !merchant.bank_account) {
      return {
        ok: false,
        message: 'Verified bank details are required before payouts can go live.',
      };
    }
    const ps = await paystackPost('/subaccount', {
      business_name: merchant.business_name,
      settlement_bank: merchant.bank_code,
      account_number: merchant.bank_account,
      percentage_charge: opts.platformFeePercent,
    });
    if (!ps?.status) {
      return { ok: false, message: String(ps?.message || 'Paystack rejected subaccount creation') };
    }
    subaccountCode = (ps.data as { subaccount_code?: string })?.subaccount_code ?? null;
  }

  if (!subaccountCode) {
    return { ok: false, message: 'Could not determine a Paystack subaccount code' };
  }

  const { data: existingTag } = await admin
    .from('nfc_tags')
    .select('tag_code')
    .eq('merchant_id', merchantId)
    .maybeSingle();
  const tagCode = existingTag?.tag_code ?? `RFP-${crypto.randomUUID().slice(0, 8).toUpperCase()}`;

  await admin
    .from('merchants')
    .update({ paystack_subaccount: subaccountCode, status: 'approved' })
    .eq('id', merchantId);

  // Off Menu shares this merchants row — keep application queue + public profile in sync.
  await admin
    .from('off_menu_vendor_applications')
    .update({ status: 'approved', updated_at: new Date().toISOString() })
    .eq('merchant_id', merchantId)
    .in('status', ['pending', 'submitted']);
  await admin
    .from('merchants')
    .update({ profile_public: true })
    .eq('id', merchantId)
    .eq('signup_vertical', 'off_menu');

  if (!existingTag) {
    await admin.from('nfc_tags').insert({ merchant_id: merchantId, tag_code: tagCode, status: 'active' });
  }

  await admin.from('admin_actions').insert({
    action_type: opts.actorEmail ? 'approve_merchant' : 'auto_approve_merchant',
    merchant_id: merchantId,
    actor_email: opts.actorEmail ?? null,
    decision_reason: opts.decisionReason || 'Automated approval after bank and business verification',
    decision_notes: opts.decisionNotes ?? null,
    compliance_snapshot: {
      legal_status: merchant.legal_status,
      permit_number: merchant.permit_number,
      permit_expiry: merchant.permit_expiry,
      offering_type: merchant.offering_type,
      primary_products: merchant.primary_products,
      expected_monthly_volume: merchant.expected_monthly_volume,
      sells_restricted_goods: merchant.sells_restricted_goods,
      risk_level: merchant.risk_level,
      account_verified: merchant.account_verified,
      subaccount_code: subaccountCode,
      auto: !opts.actorEmail,
    },
  });

  if (merchant.email) {
    await opts.sendWelcomeEmail({
      email: String(merchant.email),
      businessName: String(merchant.business_name),
      tagCode,
    });
  }

  return { ok: true, subaccount: subaccountCode, tag_code: tagCode };
}

export async function tryAutoApproveMerchant(
  admin: SupabaseClient,
  paystackPost: (path: string, body: unknown) => Promise<Record<string, unknown>>,
  opts: {
    merchantId: string;
    platformFeePercent: number;
    appUrl: string;
    sendWelcomeEmail: (args: {
      email: string;
      businessName: string;
      tagCode: string;
    }) => Promise<void>;
  },
): Promise<{ approved: boolean; blockers?: string[]; subaccount?: string | null }> {
  const { data: merchant } = await admin
    .from('merchants')
    .select(
      'id, status, business_name, email, owner_name, account_name, account_verified, account_verified_by, bank_code, bank_account, kyc_doc, legal_status, permit_number, sells_restricted_goods, paystack_subaccount',
    )
    .eq('id', opts.merchantId)
    .maybeSingle();

  if (!merchant) return { approved: false, blockers: ['merchant_not_found'] };
  if (merchant.status === 'approved') {
    return { approved: true, subaccount: merchant.paystack_subaccount };
  }

  const { count } = await admin
    .from('merchant_documents')
    .select('id', { count: 'exact', head: true })
    .eq('merchant_id', opts.merchantId);

  const assessment = assessMerchantForAutoApprove(
    merchant as MerchantAutoApproveRow,
    count ?? 0,
  );
  if (!assessment.eligible) {
    return { approved: false, blockers: assessment.blockers };
  }

  const provision = await provisionMerchantPayouts(admin, paystackPost, {
    merchantId: opts.merchantId,
    platformFeePercent: opts.platformFeePercent,
    decisionReason: `Auto-approved: ${assessment.reasons.join(', ')}`,
    sendWelcomeEmail: opts.sendWelcomeEmail,
  });

  if (!provision.ok) {
    return { approved: false, blockers: [provision.message || 'provision_failed'] };
  }

  return { approved: true, subaccount: provision.subaccount };
}

import { minChargeMessage, minChargeSubunits } from './paymentLimits.ts';

const PAYSTACK_BASE = 'https://api.paystack.co';

export async function paystackGet(secret: string, path: string) {
  const res = await fetch(`${PAYSTACK_BASE}${path}`, {
    headers: { Authorization: `Bearer ${secret}` },
  });
  const json = await res.json().catch(() => ({}));
  if (!res.ok || json?.status === false) {
    return {
      ok: false,
      message: (json as { message?: string }).message || res.statusText,
      data: (json as { data?: unknown }).data,
    };
  }
  return { ok: true, data: (json as { data?: unknown }).data };
}

export async function paystackPost(secret: string, path: string, body: unknown) {
  const res = await fetch(`${PAYSTACK_BASE}${path}`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${secret}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(body),
  });
  const json = await res.json().catch(() => ({}));
  if (!res.ok || json?.status === false) {
    return {
      ok: false,
      message: (json as { message?: string }).message || res.statusText,
      data: (json as { data?: unknown }).data,
    };
  }
  return { ok: true, data: (json as { data?: unknown }).data };
}

export async function paystackPut(secret: string, path: string, body: unknown) {
  const res = await fetch(`${PAYSTACK_BASE}${path}`, {
    method: 'PUT',
    headers: {
      Authorization: `Bearer ${secret}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(body),
  });
  const json = await res.json().catch(() => ({}));
  if (!res.ok || json?.status === false) {
    return {
      ok: false,
      message: (json as { message?: string }).message || res.statusText,
      data: (json as { data?: unknown }).data,
    };
  }
  return { ok: true, data: (json as { data?: unknown }).data };
}

/** Master Paystack integration balance (major units, e.g. ZAR). */
export async function fetchPaystackBalance(secret: string) {
  const r = await paystackGet(secret, '/balance');
  if (!r.ok) return r;
  const rows = (r.data as Array<{ balance?: number; currency?: string }>) ?? [];
  const zar = rows.find((x) => String(x.currency ?? '').toUpperCase() === 'ZAR') ?? rows[0];
  const balanceSub = Number(zar?.balance ?? 0);
  return {
    ok: true,
    balance: balanceSub / 100,
    currency: String(zar?.currency ?? 'ZAR').toUpperCase(),
    raw: rows,
  };
}

export type CreateRecipientInput = {
  name: string;
  account_number: string;
  bank_code: string;
  currency?: string;
};

export async function createPaystackTransferRecipient(secret: string, input: CreateRecipientInput) {
  const currency = String(input.currency ?? 'ZAR').toUpperCase();
  const type = currency === 'ZAR' ? 'basa' : 'nuban';
  return await paystackPost(secret, '/transferrecipient', {
    type,
    name: input.name,
    account_number: input.account_number,
    bank_code: input.bank_code,
    currency,
  });
}

export type InitiateTransferInput = {
  amountMajor: number;
  recipientCode: string;
  reason: string;
  reference: string;
  currency?: string;
  merchantId?: string;
};

export async function initiatePaystackTransfer(secret: string, input: InitiateTransferInput) {
  const amountSub = Math.round(input.amountMajor * 100);
  if (amountSub < 100) {
    return { ok: false, message: 'Minimum transfer amount is R1.00' };
  }
  return await paystackPost(secret, '/transfer', {
    source: 'balance',
    amount: amountSub,
    recipient: input.recipientCode,
    reason: input.reason.slice(0, 100) || 'RedFace transfer',
    reference: input.reference,
    currency: String(input.currency ?? 'ZAR').toUpperCase(),
    metadata: input.merchantId ? { merchant_id: input.merchantId } : {},
  });
}

export type ChargeAuthorizationInput = {
  email: string;
  amountMajor: number;
  authorizationCode: string;
  reference: string;
  currency?: string;
  metadata?: Record<string, unknown>;
  subaccount?: string;
  splitCode?: string;
  transactionCharge?: number;
};

export async function chargePaystackAuthorization(secret: string, input: ChargeAuthorizationInput) {
  const amountSub = Math.round(input.amountMajor * 100);
  const currency = String(input.currency ?? 'ZAR').toUpperCase();
  const minSub = minChargeSubunits(currency);
  if (amountSub < minSub) {
    return { ok: false, message: minChargeMessage(currency) };
  }
  const body: Record<string, unknown> = {
    email: input.email,
    amount: amountSub,
    authorization_code: input.authorizationCode,
    reference: input.reference,
    currency: String(input.currency ?? 'ZAR').toUpperCase(),
    metadata: input.metadata ?? {},
  };
  if (input.splitCode) {
    body.split_code = input.splitCode;
  } else if (input.subaccount) {
    body.subaccount = input.subaccount;
    body.bearer = 'subaccount';
    if (input.transactionCharge && input.transactionCharge > 0) {
      body.transaction_charge = input.transactionCharge;
    }
  }
  return await paystackPost(secret, '/transaction/charge_authorization', body);
}

export type ChargeCardInput = {
  email: string;
  amountMajor: number;
  reference: string;
  currency?: string;
  card: {
    number: string;
    cvv: string;
